css:
.loader {
  width: fit-content;
  font-size: 34px;
  font-family: monospace;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #4f46e5);
  background: linear-gradient(90deg,var(--loader-color, #4f46e5),var(--loader-secondary-color, #a5b4fc)) 0/0 100% no-repeat text;
  animation: l11 2s steps(8,jump-none) infinite;
}
.loader:before {
  content: "Loading";
}
@keyframes l11 {
  to {background-size: 100% 100%}
}
